import { useState, useEffect } from "react";
import "./Recruitment.css";

function Designations() {

  const [title, setTitle] = useState("");
  const [list, setList] = useState([]);

  // Load saved roles on page load
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("designations")) || [];
    setList(saved);
  }, []);

  const handleCreate = () => {
    if (!title.trim()) return alert("Please enter designation");

    // avoid duplicates
    const exists = list.some(
      (d) => d.title.toLowerCase() === title.toLowerCase()
    );

    if (exists) {
      alert("This designation already exists");
      return;
    }

    const newItem = {
      id: list.length + 1,
      title
    };

    const updatedList = [...list, newItem];

    setList(updatedList);

    // SAVE PERMANENTLY
    localStorage.setItem("designations", JSON.stringify(updatedList));

    setTitle("");

    alert("Designation Created Successfully");
  };

  return (
    <div className="designation-container">
      <h2>Generate Employee Designation</h2>

      <div className="designation-form">
        <input
          type="text"
          placeholder="Enter Designation e.g Manager"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <button onClick={handleCreate}>
          Create
        </button>
      </div>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Designation Title</th>
          </tr>
        </thead>

        <tbody>
          {list.length === 0 ? (
            <tr>
              <td colSpan="2">No Designations Created Yet</td>
            </tr>
          ) : (
            list.map((d, index) => (
              <tr key={index}>
                <td>{index + 1}</td>
                <td>{d.title}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default Designations;
